UPDATE `users`
SET `roleId` = (SELECT `id` FROM `roles` WHERE `name` = 'huvudadmin' LIMIT 1)
WHERE `email` = 'thomas.soderberg@gmail.com' OR `role` = 'admin';

COMMIT;

START TRANSACTION;

CREATE TABLE IF NOT EXISTS `news` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `content` text NOT NULL,
  `imageUrl` text NULL,
  `authorId` int NULL,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `publishedAt` timestamp NULL,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `membership_applications` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `email` varchar(320) NOT NULL,
  `phone` varchar(20) NULL,
  `message` text NULL,
  `status` enum('pending','approved','rejected') NOT NULL DEFAULT 'pending',
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `gallery_photos` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `description` text NULL,
  `imageUrl` text NOT NULL,
  `thumbnailUrl` text NULL,
  `mediumUrl` text NULL,
  `originalUrl` text NULL,
  `category` varchar(100) NULL,
  `uploadedBy` int NULL,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `events` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `description` text NULL,
  `eventDate` timestamp NOT NULL,
  `eventTime` varchar(10) NULL,
  `location` varchar(255) NULL,
  `type` varchar(100) NULL,
  `maxParticipants` int NULL,
  `registrationDeadline` timestamp NULL,
  `status` enum('draft','published','cancelled','completed') NOT NULL DEFAULT 'published',
  `allowWaitlist` int NOT NULL DEFAULT 0,
  `createdBy` int NULL,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `event_registrations` (
  `id` int NOT NULL AUTO_INCREMENT,
  `eventId` int NOT NULL,
  `userId` int NOT NULL,
  `status` enum('registered','waitlist','cancelled') NOT NULL DEFAULT 'registered',
  `notes` text NULL,
  `registeredAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `cancelledAt` timestamp NULL,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `payment_confirmations` (
  `id` int NOT NULL AUTO_INCREMENT,
  `userId` int NOT NULL,
  `amount` varchar(20) NOT NULL,
  `paymentType` varchar(50) NOT NULL DEFAULT 'membership_fee',
  `paymentYear` int NOT NULL,
  `receiptUrl` text NULL,
  `status` enum('pending','verified','rejected') NOT NULL DEFAULT 'pending',
  `notes` text NULL,
  `verifiedBy` int NULL,
  `verifiedAt` timestamp NULL,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `page_content` (
  `id` int NOT NULL AUTO_INCREMENT,
  `page` varchar(100) NOT NULL,
  `sectionKey` varchar(100) NOT NULL,
  `type` varchar(50) NOT NULL,
  `content` text NULL,
  `order` int NOT NULL DEFAULT 0,
  `published` int NOT NULL DEFAULT 1,
  `updatedBy` int NULL,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `site_settings` (
  `id` int NOT NULL AUTO_INCREMENT,
  `key` varchar(100) NOT NULL,
  `value` text NOT NULL,
  `type` varchar(50) NOT NULL DEFAULT 'text',
  `updatedBy` int NULL,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `site_settings_key_unique` (`key`)
);

CREATE TABLE IF NOT EXISTS `board_members` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `role` varchar(255) NOT NULL,
  `phone` varchar(50) NULL,
  `email` varchar(320) NULL,
  `photo` text NULL,
  `order` int NOT NULL DEFAULT 0,
  `active` int NOT NULL DEFAULT 1,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `content_history` (
  `id` int NOT NULL AUTO_INCREMENT,
  `contentId` int NOT NULL,
  `content` text NULL,
  `updatedBy` int NULL,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `documents` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `description` text NULL,
  `fileUrl` text NOT NULL,
  `fileSize` int NULL,
  `category` enum('stadgar','protokoll','informationsblad','arsmoten','ovrigt') NOT NULL,
  `accessLevel` enum('public','members_only','admin_only') NOT NULL DEFAULT 'members_only',
  `uploadedBy` int NULL,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
);

