INSERT INTO `page_content` (`id`, `page`, `sectionKey`, `type`, `content`, `order`, `published`, `updatedBy`, `updatedAt`)
VALUES (4, 'home', 'about_content', 'html', '<p>Föreningen Gamla SSK-are bildades den 25 augusti 1937 (1936 beslutades att starta en förening, men den bildades först året därpå). Dess förste ordförande var Carl Abrahamsson, ''Calle Aber'' kallad, och som gett namnet till SSK:s restaurang fr.o.m. hösten 2021.</p><p>Föreningen, som för närvarande har drygt 300 medlemmar (bl.a. Anders Eldebrink, Mats Hallin, Kjell Svensson och Björn Borg….), är en stödförening till moderklubben SSK.</p><p>Pengarna till moderföreningen kommer främst från medlemmarnas ideella arbete med bingo. Vi säljer bingolotter och sverigelotter på ICA Maxi Vasa och Moraberg samt Stora Coop Vasa.</p>', 1, 1, 1, '2025-11-15 18:50:06' )
ON DUPLICATE KEY UPDATE
  `page` = VALUES(`page`),
  `sectionKey` = VALUES(`sectionKey`),
  `type` = VALUES(`type`),
  `content` = VALUES(`content`),
  `order` = VALUES(`order`),
  `published` = VALUES(`published`),
  `updatedBy` = VALUES(`updatedBy`),
  `updatedAt` = VALUES(`updatedAt`);

