INSERT INTO `page_content` (`id`, `page`, `sectionKey`, `type`, `content`, `order`, `published`, `updatedBy`, `updatedAt`)
VALUES (30001, 'statutes', 'intro', 'html', '<p>Föreningen Gamla SSK-are är en stödförening till Södertälje SK som bildades 1937. Vi arbetar ideellt för att stödja moderklubben ekonomiskt och socialt genom olika aktiviteter, främst försäljning av folkspels-bingolotter.</p>', 0, 1, NULL, '2025-11-14 16:07:17' )
ON DUPLICATE KEY UPDATE
